// **********************************************************
// @description Enrich Response with UI Metadata from Cache
//
// @param   {object} data - computed result or input payload
// @param   {object} $    - {tenant, paramsId, params}
// @param   {object} ctx  - opentracing context
// @param   {object} this - ARES
//
// @return  {object} data - data object enriched
// **********************************************************

const { tenant, params } = $;
const MPXEndpoint =
  "https://feed.entertainment.tv.theplatform.eu/f/PR1GhC/mediaset-prod-public-url?fields=guid,title,description,programType,thumbnails,media.expirationDate,media.availableDate,media.publicUrl,longDescription,year,seriesId,tvSeasonEpisodeNumber,tvSeasonNumber,mediasetprogram$videoPageUrl,mediasetprogram$numberOfViews,mediasetprogram$genres,ratings,tags,mediasetprogram$duration,mediasetprogram$pageUrl,mediasetprogram$publishInfo,mediasetprogram$publishInfo_lastPublished,mediasetprogram$brandDescription,mediasetprogram$brandId,mediasetprogram$brandTitle,mediasetprogram$subBrandId,mediasetprogram$subBrandTitle,mediasetprogram$episodeId,seriesId,mediasetprogram$sourceAspectRatio,mediasetprogram$subBrandDescription&byGuid=";
const tenantId = params.tenant;
const keys = [];
const ids = [];
const types = new Map();
const getKey = (contentType, id) => `{${tenantId}:${contentType}:ux}:${id}`;

// **************************************
// Get ids, contentType for every element
// to process and generate Cache Key
// **************************************
for (let k = 0, length = data.blocks.length; k < length; k++) {
  const block = data.blocks[k];
  const contentType = block._contentType;

  const paramsTyped = params.content.types[contentType];

  if (!paramsTyped) continue;

  const contentIdField = paramsTyped.contentIdField;

  for (let i = 0, length = block.items.length; i < length; i++) {
    const item = block.items[i];
    const id = item[contentIdField];

    keys.push(getKey(contentType, id));
    ids.push(id);
    types.set(id, contentType);
  }
}

if (!keys.length) return data;

// **************************************
// Get UIItems from Cache and check for
// missing items
// **************************************
const values = await this.cache.getKeys(keys);
const UIMap = new Map();
const missing = [];

for (let i = 0, length = values.length; i < length; i++) {
  const id = ids[i];
  const value = values[i];

  if (!value) missing.push(id);
  else UIMap.set(id, value);
}

// **************************************
// If some UI Enrichment is missing then
// grab it from MPX and put it in cache
// **************************************
if (missing.length > 0) {
  const pipeline = this.cache.getPipeline();
  const url = MPXEndpoint + missing.join("|");
  const UIRes = (await this.axios(url)).data;

  for (let uiIndex = 0, length = UIRes.entryCount; uiIndex < length; uiIndex++) {
    const uxItem = UIRes.entries[uiIndex];

    if (!uxItem) continue;

    const id = uxItem.guid;
    const contentType = types.get(id);
    const key = getKey(contentType, id);

    UIMap.set(id, uxItem);
    pipeline.set(key, JSON.stringify(uxItem), "EX", 86400); // 1 day
  }

  pipeline.exec();
}

// **************************************
// Enrich Blocks with UIItems
// **************************************
for (let blockIndex = 0, length = data.blocks.length; blockIndex < length; blockIndex++) {
  const block = data.blocks[blockIndex];
  const contentType = block._contentType;

  const paramsTyped = params.content.types[contentType];
  if (!paramsTyped) continue;

  const contentIdField = paramsTyped.contentIdField;

  for (let itemIndex = 0, length = block.items.length; itemIndex < length; itemIndex++) {
    const item = block.items[itemIndex];
    const id = item[contentIdField];
    const uiEnrich = UIMap.get(id);

    if (!uiEnrich) continue;

    const enriched = typeof uiEnrich === "object" ? uiEnrich : JSON.parse(uiEnrich);

    data.blocks[blockIndex].items[itemIndex] = { ...item, ...enriched };
  }
}

return data;
